import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';

// Proveedor de Contexto
import { AuthProvider, useAuth } from './context/AuthContext';

// Importación de Componentes
import Header from './components/Header';
import Home from './components/Home';
import Login from './components/Login';
import Registro from './components/Registro';
import Dashboard from './components/Dashboard';
import GestionOfertas from './components/GestionOfertas';
import PanelCliente from './components/PanelCliente';

// Componente para proteger rutas (Helper interno)
const RutaPrivada = ({ children, rolRequerido }) => {
  const { user, loading } = useAuth();

  if (loading) return <div>Cargando...</div>; // O un Spinner

  if (!user) return <Navigate to="/login" />;

  if (rolRequerido && user.rol !== rolRequerido) {
    return <Navigate to="/" />;
  }

  return children;
};

function App() {
  return (
    <AuthProvider>
      <Router>
        {/* El Header ahora no necesita props, usará useAuth() por dentro */}
        <Header /> 

        <Routes>
          {/* RUTA PÚBLICA */}
          <Route path="/" element={<Home />} />

          {/* RUTAS DE AUTENTICACIÓN */}
          <Route path="/login" element={<Login />} />
          <Route path="/registro" element={<Registro />} />

          {/* RUTAS PRIVADAS VENDEDOR */}
          <Route 
            path="/dashboard" 
            element={
              <RutaPrivada rolRequerido="vendedor">
                <Dashboard />
              </RutaPrivada>
            } 
          />
          <Route 
            path="/ofertas/:id" 
            element={
              <RutaPrivada rolRequerido="vendedor">
                <GestionOfertas />
              </RutaPrivada>
            } 
          />

          {/* RUTAS PRIVADAS CLIENTE */}
          <Route 
            path="/panel-cliente" 
            element={
              <RutaPrivada rolRequerido="cliente">
                <PanelCliente />
              </RutaPrivada>
            } 
          />

          {/* REDIRECCIÓN POR DEFECTO */}
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
